// Extract event data from router payload
const input = $input.first().json;

// Router sends: { event_id, event_type, project_id, payload }
const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

// Step key is project-specific
const stepKey = `drive_tree:${projectId}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    year_folder_id: payload.year_folder_id,
    year: payload.year,
    step_key: stepKey
  }
};

// Build folder name: P-2025-001 SAGA Musterstraße 1
const project = $input.first().json;
const eventData = $('Parse Event Data').first().json;

// Extract components
const projectNumber = project.project_number || 'UNKNOWN';
const clientName = project.client_name || 'Kunde';
const street = project.object_street || project.name || 'Projekt';

// Build folder name
const folderName = `${projectNumber} ${clientName} ${street}`;

// Subfolder definitions (9 folders)
const subfolders = [
  { name: '01_Auftrag', type: 'AUFTRAG' },
  { name: '02_Angebot', type: 'ANGEBOT' },
  { name: '03_Aufmass', type: 'AUFMASS' },
  { name: '04_Rechnung', type: 'RECHNUNG' },
  { name: '05_Bauakte', type: 'BAUAKTE' },
  { name: '06_Protokolle', type: 'PROTOKOLLE' },
  { name: '07_Fotos', type: 'FOTOS' },
  { name: '08_Kommunikation', type: 'KOMMUNIKATION' },
  { name: '09_Sonstiges', type: 'SONSTIGES' }
];

return {
  json: {
    project_id: eventData.project_id,
    event_id: eventData.event_id,
    year_folder_id: eventData.year_folder_id,
    step_key: eventData.step_key,
    folder_name: folderName,
    subfolders: subfolders
  }
};

// Extract project folder ID and prepare for subfolders
const createResult = $input.first().json;
const prepData = $('Prepare Folder Structure').first().json;

return {
  json: {
    project_id: prepData.project_id,
    event_id: prepData.event_id,
    step_key: prepData.step_key,
    project_folder_id: createResult.id,
    project_folder_name: createResult.name,
    subfolders: prepData.subfolders
  }
};

// Create items for each subfolder
const data = $input.first().json;

// Return an array item for each subfolder
return data.subfolders.map(sf => ({
  json: {
    project_id: data.project_id,
    event_id: data.event_id,
    step_key: data.step_key,
    project_folder_id: data.project_folder_id,
    project_folder_name: data.project_folder_name,
    subfolder_name: sf.name,
    subfolder_type: sf.type
  }
}));

// Collect all subfolder results and prepare DB inserts
const items = $input.all();
const firstItem = $('Split to Subfolders').first().json;

// Map results to folder records
const folderRecords = items.map((item, idx) => {
  const inputItem = $('Split to Subfolders').all()[idx].json;
  return {
    folder_type: inputItem.subfolder_type,
    folder_name: inputItem.subfolder_name,
    drive_folder_id: item.json.id
  };
});

// Build SQL for inserting all folders
const projectRootInsert = `INSERT INTO project_drive_folders (project_id, folder_type, folder_name, drive_folder_id, is_created, created_in_drive_at)
VALUES ('${firstItem.project_id}'::uuid, 'PROJECT_ROOT', '${firstItem.project_folder_name.replace(/'/g, "''")}', '${firstItem.project_folder_id}', true, now())`;

const subfolderInserts = folderRecords.map(f => 
  `INSERT INTO project_drive_folders (project_id, folder_type, folder_name, drive_folder_id, is_created, created_in_drive_at)
  VALUES ('${firstItem.project_id}'::uuid, '${f.folder_type}', '${f.folder_name}', '${f.drive_folder_id}', true, now())`
).join(';\n');

const updateProject = `UPDATE projects SET drive_folder_id = '${firstItem.project_folder_id}' WHERE id = '${firstItem.project_id}'::uuid`;

return {
  json: {
    project_id: firstItem.project_id,
    event_id: firstItem.event_id,
    step_key: firstItem.step_key,
    project_folder_id: firstItem.project_folder_id,
    project_folder_name: firstItem.project_folder_name,
    subfolder_count: folderRecords.length,
    sql: `${projectRootInsert};\n${subfolderInserts};\n${updateProject};`,
    folder_records: folderRecords
  }
};

