-- Mark input event as processed
DO $$ BEGIN
  UPDATE events SET processed_at = now() WHERE id = '{{ $json.event_id }}'::uuid;
EXCEPTION WHEN invalid_text_representation THEN NULL;
END $$;

-- Emit next event
INSERT INTO events (event_type, project_id, payload, source_system, source_flow)
VALUES (
  'DRIVE_TREE_CREATED',
  '{{ $json.project_id }}'::uuid,
  '{"project_folder_id": "{{ $json.project_folder_id }}"}',
  'n8n',
  'M1_04b_Create_Project_Tree'
)
RETURNING id, event_type::text, project_id;

parameters.jsCode:
return {
  json: {
    status: 'success',
    message: 'DRIVE_TREE_CREATED emitted',
    project_id: $input.first().json.project_id,
    project_folder_id: $('Prepare Event Payload').first().json.project_folder_id
  }
};

// Step already done or in progress by another run
const claimResult = $input.first().json;
const eventData = $('Parse Event Data').first().json;

if (claimResult.current_status === 'DONE') {
  // Already done - emit event with existing payload
  return {
    json: {
      action: 'skip_but_emit',
      reason: 'Project tree already exists',
      project_folder_id: claimResult.existing_payload?.project_folder_id || null,
      project_id: eventData.project_id,
      event_id: eventData.event_id
    }
  };
}

// IN_PROGRESS by another run - do nothing
return {
  json: {
    action: 'exit',
    reason: 'Step in progress by another run',
    current_status: claimResult.current_status
  }
};

// Prepare event for skip path
const data = $input.first().json;

return {
  json: {
    project_id: data.project_id,
    event_id: data.event_id,
    project_folder_id: data.project_folder_id
  }
};

return {
  json: {
    status: 'success',
    message: 'DRIVE_TREE_CREATED emitted (reused folder)',
    project_id: $input.first().json.project_id
  }
};

// Exit - another run is handling this
return {
  json: {
    status: 'skipped',
    message: 'Step in progress by another run'
  }
};

